uniform float uDepth;
uniform float uAxis;
uniform float uDir;
out vec4 fragColor;
void main(){
    vec2 uv = vUV.st;
    float t = (uAxis > 0.5 ? uv.y : uv.x);
    if (uDir < 0.0) t = 1.0 - t;
    int idx = int(clamp(t * (uDepth - 1.0), 0.0, uDepth - 1.0));
    fragColor = TDOutputSwizzle(texelFetch(sTD2DArrayInputs[0], ivec3(ivec2(gl_FragCoord.xy), idx), 0));
}
